using Microsoft.EntityFrameworkCore;
using Shopfront.API.Models;

namespace Shopfront.API.Data;

public static class AgentSeeder
{
    public static async Task SeedAsync(ShopfrontDbContext db)
    {
        // Wipe and re-seed to keep in sync with the source spreadsheet
        var existing = await db.Agents.ToListAsync();
        if (existing.Count == AllAgents.Count && existing.All(a => !string.IsNullOrEmpty(a.Region))) return;

        db.Agents.RemoveRange(existing);
        await db.SaveChangesAsync();

        foreach (var a in AllAgents)
            a.Id = Guid.NewGuid();

        db.Agents.AddRange(AllAgents);
        await db.SaveChangesAsync();

        Console.WriteLine($"Seeded {AllAgents.Count} agents.");
    }

